/**
 * Merges this rectangle with a point. The rectangle should not have negative
 * width or negative height.
 *
 * @param x the x coordinate of the point
 * @param y the y coordinate of the point
 * @return this rectangle for chaining
 */
public RectangleMutant merge(float x, float y) {
    float minX = Math.min(this.x, x);
    float maxX = Math.max(this.x + width, x);
    this.x = minX;
    this.width = maxX - minX;
    float minY = Math.min(this.y, y);
    float maxY = Math.max(this.y + height, y);
    this.y = minY;
    this.height = maxY - minY;
    return this;
}
